import{_ as n,o as s,c as l,j as a,a as t}from"./chunks/framework.CVjg771q.js";const f=JSON.parse('{"title":"生肖 · 虎","description":"寅虎——百兽之王，凶猛彪悍","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 虎","description":"寅虎——百兽之王，凶猛彪悍"},"headers":[],"relativePath":"changshi/shengxiao/hu.md","filePath":"changshi/shengxiao/hu.md","lastUpdated":1779783531000}'),r={name:"changshi/shengxiao/hu.md"};function o(i,e,h,c,d,p){return s(),l("div",null,[...e[0]||(e[0]=[a("h1",{id:"寅虎",tabindex:"-1"},[t("寅虎 "),a("a",{class:"header-anchor",href:"#寅虎","aria-label":'Permalink to "寅虎"'},"​")],-1),a("blockquote",null,[a("p",null,"地支「寅」· 寅时（03:00–05:00）· 五行属木 · 阴阳为阳")],-1),a("p",null,"虎被誉为百兽之王，凶猛彪悍，寅时老虎最活跃、最凶猛。汉字中的「王」字就是根据老虎前额上的花纹创造的。古人以「虎将」「虎士」称军人，调兵遣将的虎符、震慑敌人的虎形旗都融入了虎的形象。虎还被当作驱难辟邪之物。",-1),a("h2",{id:"生肖故事-三横一竖成王字",tabindex:"-1"},[t("生肖故事：三横一竖成王字 "),a("a",{class:"header-anchor",href:"#生肖故事-三横一竖成王字","aria-label":'Permalink to "生肖故事：三横一竖成王字"'},"​")],-1),a("p",null,"相传老虎原是一种普通动物，从猫师傅那里学会十八般武艺后逐渐雄霸山林。玉帝听说老虎勇猛，便让它上天做了天宫的殿前卫士。",-1),a("p",null,"可自老虎上天后，人间的狮子、野猪和狗熊就为非作歹起来。玉帝又把老虎派到人间。老虎向狮子、野猪、狗熊发起挑战，最终三者都不敌老虎，只好灰溜溜藏了起来。",-1),a("p",null,"回到天宫，玉帝为奖励老虎三战三胜，在它额上刻了三条横线。后来东海龟怪骚扰人间，老虎又下凡镇压。玉帝一高兴，在老虎额前的三横中添了一竖——一个醒目的「王」字出现在老虎前额。此后玉帝封老虎为「百兽之王」。选十二生肖时，土地神和众神仙都举荐老虎，老虎便入选了。",-1)])])}const m=n(r,[["render",o]]);export{f as __pageData,m as default};
